esc_latex_text <- function(x){
  x <- gsub('`','',x,fixed=TRUE)
  x <- gsub('\\\\','\\\\textbackslash{}',x)
  x <- gsub('([#%&_{}])','\\\\\\1',x,perl=TRUE)
  x
}
tex <- c('\\documentclass[11pt]{article}','\\usepackage[margin=1in]{geometry}','\\usepackage{graphicx}','\\usepackage{hyperref}','\\usepackage{amsmath}','\\title{Economic Complexity and Structural Transformation in Latin America}','\\author{Monica Cueto Tapia}','\\date{2026-07-11}','\\begin{document}','\\maketitle')
in_yaml <- FALSE
for (ln in q) {
  if (ln == '---') { in_yaml <- !in_yaml; next }
  if (in_yaml || grepl('^(title|subtitle|author|date|format|bibliography):', ln)) next
  if (!nzchar(trimws(ln))) { tex <- c(tex,''); next }
  if (grepl('^# ', ln)) tex <- c(tex, paste0('\\section{', esc_latex_text(sub('^# ', '', ln)), '}'))
  else if (grepl('^## ', ln)) tex <- c(tex, paste0('\\subsection{', esc_latex_text(sub('^## ', '', ln)), '}'))
  else if (grepl('^!\\[', ln)) { alt <- sub('^!\\[([^]]*)\\].*$', '\\1', ln); src <- sub('^!\\[[^]]*\\]\\(([^)]+)\\).*$', '\\1', ln); tex <- c(tex, '\\begin{figure}[ht]', '\\centering', paste0('\\includegraphics[width=0.92\\linewidth]{', src, '}'), paste0('\\caption{', esc_latex_text(alt), '}'), '\\end{figure}') }
  else if (grepl('^\\|', ln)) next
  else tex <- c(tex, esc_latex_text(ln), '')
}
tex <- c(tex, '\\end{document}')
write_utf8(tex, p('paper/main.tex'))
