draw_banner <- function(file, type='png') {
  if (type=='png') png(file, width=1600, height=500, res=160) else svg(file, width=10, height=3.125)
  par(mar=c(0,0,0,0), bg='white'); plot.new(); plot.window(xlim=c(0,1), ylim=c(0,1))
  rect(0,0,1,1,col='#f7f7f4',border=NA); rect(0,0,1,.08,col='#b21f2d',border=NA)
  pts <- scale(xy); pts <- cbind(0.56 + 0.36*pts[,1], 0.13 + 0.74*pts[,2])
  if (!is.null(g)) { ed <- igraph::as_edgelist(g); for(i in seq_len(min(nrow(ed),350))) { a<-match(ed[i,1], igraph::V(g)$name); b<-match(ed[i,2], igraph::V(g)$name); segments(pts[a,1],pts[a,2],pts[b,1],pts[b,2],col=adjustcolor('#7a8793',.22),lwd=.6) } }
  points(pts[,1], pts[,2], pch=21, bg=adjustcolor('#2166ac',.75), col='white', cex=.65, lwd=.2)
  sel <- sample(seq_len(nrow(pts)), min(24,nrow(pts))); points(pts[sel,1], pts[sel,2], pch=21, bg='#b21f2d', col='white', cex=.85, lwd=.2)
  text(.05,.68,'Economic Complexity',adj=0,cex=2.2,font=2,col='#17233c')
  text(.05,.54,'and Structural Transformation',adj=0,cex=1.75,font=2,col='#17233c')
  text(.05,.39,'Latin America and Bolivia diversification opportunities',adj=0,cex=.95,col='#3b4652')
  text(.05,.25,'Monica Cueto Tapia',adj=0,cex=.88,col='#3b4652')
  text(.05,.17,'Product Space | RCA | ECI | Policy screening',adj=0,cex=.78,col='#5a6673')
  dev.off()
}
